"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[67175],{62766:(e,n,a)=>{a.r(n),a.d(n,{data:()=>i});const i={key:"v-1c79c06e",path:"/vue/vue3/%E4%BB%93%E5%BA%93%E6%9E%84%E5%BB%BA.html",title:"learn+yarn实现monorepo仓库构建",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"前言",slug:"前言",children:[{level:3,title:"（1）建立多个git仓库，单独管理每个工程；",slug:"_1-建立多个git仓库-单独管理每个工程",children:[]},{level:3,title:"（2）通过 lerna + yarn 实现 monorepo 管理；",slug:"_2-通过-lerna-yarn-实现-monorepo-管理",children:[]}]},{level:2,title:"技术栈",slug:"技术栈",children:[]},{level:2,title:"步骤",slug:"步骤",children:[{level:3,title:"1.创建包",slug:"_1-创建包",children:[]},{level:3,title:"2.创建项目",slug:"_2-创建项目",children:[]},{level:3,title:"3.在package.json中设置工作区",slug:"_3-在package-json中设置工作区",children:[]},{level:3,title:"4.修改lerna.json",slug:"_4-修改lerna-json",children:[]},{level:3,title:"5.统一修改版本号",slug:"_5-统一修改版本号",children:[]},{level:3,title:"6.统一发布",slug:"_6-统一发布",children:[]}]},{level:2,title:"参考资料",slug:"参考资料",children:[]}],git:{updatedTime:1653451151e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"vue/vue3/仓库构建.md"}},78166:(e,n,a)=>{a.r(n),a.d(n,{default:()=>r});const i=(0,a(57293).uE)('<h1 id="learn-yarn实现monorepo仓库构建" tabindex="-1"><a class="header-anchor" href="#learn-yarn实现monorepo仓库构建" aria-hidden="true">#</a> learn+yarn实现monorepo仓库构建</h1><h2 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h2><p>我们一个项目可能存在多个工程，一个项目分前后端工程，后端和前端都可能存在多个工程，所以对于这种情况，目前个人了解下来有2种管理方案：</p><h3 id="_1-建立多个git仓库-单独管理每个工程" tabindex="-1"><a class="header-anchor" href="#_1-建立多个git仓库-单独管理每个工程" aria-hidden="true">#</a> （1）建立多个git仓库，单独管理每个工程；</h3><ul><li>优点：每个工程由于都独立，所以可以自由选择任意框架开发，互不干涉</li><li>缺点：工程多了，库多了，管理就繁琐了，这点很影响效率，维护麻烦</li></ul><h3 id="_2-通过-lerna-yarn-实现-monorepo-管理" tabindex="-1"><a class="header-anchor" href="#_2-通过-lerna-yarn-实现-monorepo-管理" aria-hidden="true">#</a> （2）通过 lerna + yarn 实现 monorepo 管理；</h3><p>一个工程中包含所有的package（这里所说的package就是原来分开管理的工程的主要部分），这样一来就只需要建立一个git仓库，把整个项目的所有前后的功能package都能一起管理了，当然这里建议最好把前后的分开为2个仓库，然后前后端单独用 lerna + yarn 实现 monorepo 管理</p><ul><li>优点：仓库少了，一次性管理所有module，每个module都可以通过learna建立关联关系，这样方便开发私有插件</li><li>缺点：要遵守相应的规范，其他我暂时还不知道</li></ul><h2 id="技术栈" tabindex="-1"><a class="header-anchor" href="#技术栈" aria-hidden="true">#</a> 技术栈</h2><p>nodejs v16.15.0</p><p>yarn v1.22.18</p><p>lerna v4.0.0</p><h2 id="步骤" tabindex="-1"><a class="header-anchor" href="#步骤" aria-hidden="true">#</a> 步骤</h2><h3 id="_1-创建包" tabindex="-1"><a class="header-anchor" href="#_1-创建包" aria-hidden="true">#</a> 1.创建包</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>git init monorepo-study &amp;&amp; cd monorepo-study\nlerna init\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202205111536957.png" alt="image-20220511153650883"></p><p>你的代码仓库目前应该是如下结构：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>monorepo-study/\n  packages/\n  package.json\n  lerna.json\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-创建项目" tabindex="-1"><a class="header-anchor" href="#_2-创建项目" aria-hidden="true">#</a> 2.创建项目</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>lerna create monorepo-study\nlerna create @monorepo-study/core\nlerna create @monorepo-study/utils\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-在package-json中设置工作区" tabindex="-1"><a class="header-anchor" href="#_3-在package-json中设置工作区" aria-hidden="true">#</a> 3.在package.json中设置工作区</h3><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code>{\n  ................\n  &quot;private&quot;: true,\n  &quot;workspaces&quot;:[\n    &quot;packages/monorepo&quot;,\n    &quot;packages/@monorepo/*&quot;\n  ]\n  .............\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>private:必须为true</li><li>workspaces:工作区路径</li></ul><h3 id="_4-修改lerna-json" tabindex="-1"><a class="header-anchor" href="#_4-修改lerna-json" aria-hidden="true">#</a> 4.修改lerna.json</h3><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code>{\n    &quot;npmClient&quot;: &quot;yarn&quot;,\n    &quot;useWorkspaces&quot;: true,\n    &quot;version&quot;: &quot;1.0.0-beta.1&quot;,\n    &quot;command&quot;: {\n      &quot;version&quot;: {\n        &quot;allowBranch&quot;: &quot;master&quot;,\n        &quot;conventionalCommits&quot;: true,\n        &quot;exact&quot;: true,\n        &quot;ignoreChanges&quot;: [&quot;**/*.md&quot;],\n        &quot;message&quot;: &quot;build: publish %s&quot;\n      }\n    }\n  }\n  \n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-统一修改版本号" tabindex="-1"><a class="header-anchor" href="#_5-统一修改版本号" aria-hidden="true">#</a> 5.统一修改版本号</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>lerna version\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_6-统一发布" tabindex="-1"><a class="header-anchor" href="#_6-统一发布" aria-hidden="true">#</a> 6.统一发布</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>lerna publish\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2><p>https://www.jianshu.com/p/0772a4c27219</p><p>learn:https://www.lernajs.cn/</p><p>[如何使用lerna管理你的仓库]https://blog.csdn.net/astonishqft/article/details/123043462</p>',33),l={},r=(0,a(63243).Z)(l,[["render",function(e,n){return i}]])},63243:(e,n)=>{n.Z=(e,n)=>{const a=e.__vccOpts||e;for(const[e,i]of n)a[e]=i;return a}}}]);